INSERT INTO `blog` (`ID`, `Name`, `heading`, `category`, `message`, `date`, `image`, `Post_date`) VALUES
(4, 'Admin', 'News and Udpates, Videos, Tutorials, Press Statements', 'Tutorials', 'Expect to find latest updates on our software platform developments, press releases and video tutorials showing you exactly how the system works. ', '01/03/2018', '2 (3).png', '2018-03-12 13:10:09'),
(5, 'Admin', 'New Customer Registration', 'Tutorials', '<iframe width=\"300\" height=\"200\" src=\"https://www.youtube.com/embed/q1a33E1B5pk\" frameborder=\"0\" allow=\"autoplay; encrypted-media\" allowfullscreen></iframe>\r\n\r\nIn this video we show you how to register a customer account, to use the merchant couriers transportation services booking platform. You simply visit our secure website at https://www.merchantcouriers.co.zw and register to become a customer.', 'Mar 12 2017', 'delivery Van1.png', '2018-03-12 13:33:52'),
(6, 'Amin', 'How To Book A Service', 'Tutorials', '<iframe width=\"300\" height=\"200\" src=\"https://www.youtube.com/embed/uGpC_81NLNY\" frameborder=\"0\" allow=\"autoplay; encrypted-media\" allowfullscreen></iframe>\r\n\r\nIn this video we show you how to book a service that you would like to use. To do this use the merchant couriers transportation services booking platform. You simply visit our secure website at https://www.merchantcouriers.co.zw  or download our mobile application and start booking. Watch video for more.', 'Mar 12 2017', 'delivery Van1.png', '2018-03-12 13:30:29'),
(7, 'Admin', 'Adding & Submitting Information For Your Booking', 'Tutorials', '<iframe width=\"300\" height=\"200\" src=\"https://www.youtube.com/embed/SSTqjdbEVp4\" frameborder=\"0\" allow=\"autoplay; encrypted-media\" allowfullscreen></iframe>\r\n\r\nIn this video we show you how to book a service by filling in our online booking form. To do this use the merchant couriers transportation services booking platform. You simply visit our secure website at https://www.merchantcouriers.co.zw  or download our mobile application and start booking. Watch video for more.', 'Mar 12 2017', 'Fleetstar app.png', '2018-03-12 13:33:19'),
(8, 'Admin', 'How to signup as a service provider', 'Tutorials', '<iframe width=\"300\" height=\"200\" src=\"https://www.youtube.com/embed/VoAcXi6E_N8\" frameborder=\"0\" allow=\"autoplay; encrypted-media\" allowfullscreen></iframe>\r\n\r\nIn this video we show you how register for a service that you would like to provide booking customers. To do this use the merchant couriers transportation registration form. You simply visit our secure website at https://www.merchantcouriers.co.zw  or download a driver mobile application and signup. Watch video for more.', 'Mar 12 2017', 'Fleetstar app.png', '2018-03-12 13:36:18'),
(9, 'Admin', 'Completing Your Signup-Service Provider', 'Tutorials', '\r\n<iframe width=\"300\" height=\"200\" src=\"https://www.youtube.com/embed/2-Rxn306_-c\" frameborder=\"0\" allow=\"autoplay; encrypted-media\" allowfullscreen></iframe>\r\n\r\nIn this video we show you how register your services that you would like to make available to customers. To do this use the merchant couriers transportation services registration page. You simply visit our secure website at https://www.merchantcouriers.co.zw  or download a driver mobile application and signup. Watch video for more.', 'Mar 12 2017', 'Fleetstar app.png', '2018-03-12 13:38:11'),
(10, 'Admin', 'Using the driver app', 'Tutorials', '<iframe width=\"300\" height=\"200\" src=\"https://www.youtube.com/embed/0e5NpHCGiZs\" frameborder=\"0\" allow=\"autoplay; encrypted-media\" allowfullscreen></iframe>\r\n\r\nIn this video we show you how to start using the merchant couriers driver app (a service provider platform to fulfill bookings) To do this use the merchant couriers transportation servicesdriver application. You simply visit our secure website at https://www.merchantcouriers.co.zw and go to Driver Login  or download the driver mobile application and login via your mobile device. Watch video for more.', 'Mar 12 2017', 'Fleetstar app.png', '2018-03-12 13:40:33'),
(11, 'Admin', 'How to pay for an order', 'Tutorials', '<iframe width=\"300\" height=\"200\" src=\"https://www.youtube.com/embed/_G41NIyiRpI\" frameborder=\"0\" allow=\"autoplay; encrypted-media\" allowfullscreen></iframe>\r\n\r\nIn this video we show you how to pay for a booked service on the merchant couriers transportation services booking platform. After booking you will receive a booking invoice. Customers are expected to pay on secure merchant platform paynow Zimbabwe soon after booking to avoid booking fulfillment delays.  Watch video for more.', 'Mar 12 2017', 'WhatsApp Image 2017-08-04 at 3.12.35 AM.jpeg', '2018-03-12 13:42:46'),
(12, 'Admin', 'Fulfilling a new booking-Service provider', 'Tutorials', '<iframe width=\"300\" height=\"200\" src=\"https://www.youtube.com/embed/1-6KISWvXN4\" frameborder=\"0\" allow=\"autoplay; encrypted-media\" allowfullscreen></iframe>\r\n\r\nIn this video we show you how to fulfill an order on your phone whenever in comes through. To do so you need to be a registered service provider and login to he driver app. In the app you will see new orders, accept the new booking and fulfill them. Make sure you are online to accept any bookings. Watch the video for more, to signup and download the driver app visit https://www.merchantcouriers.co.zw', 'Mar 12 2017', 'WhatsApp Image 2017-08-04 at 2.52.44 AM.jpeg', '2018-03-12 13:44:25'),
(13, 'Happy Zhou', 'Know the right platforms to offer transport services online', 'News', 'Economies are shifting from traditional ways of doing business to technology based platforms, and it\'s important to choose the right internet platforms for your business.<br/><br/>\r\n\r\nAs a point of observation within Zimbabwe specifically. What exactly determines success for one\'s business today? There a few key factors which we will highlight for you here that you might want to consider.<br/><br/>\r\n\r\nWhether you are an individual who owns a motorbike, car, van, or truck. You can take advantage of the online opportunity and offer transportation services, online.\r\n<br/><br/>\r\nKey #1: Your business should not only be brick and mortar or offline but online<br/><br/>\r\nIf you run any business of any kind, you have to be open to new channels and ways of growth. One such way should be ecommerce. It is important for  you to have platform where you actually have your services advertised, or booked or even purchased on the internet. As long as the website is secure, and customers are using it, its a good place to be. <br/>One of the innovations that Merchant Couriers has developed, is a platform that helps customers book a truck, taxi, tow truck or freight truck online. They need not visit your office anymore. For your transportation business, you can register on platforms like Merchant Couriers and grow your business reach.\r\n<br/><br/>\r\nKey #2: Your business should have a mobile application<br/><br/>\r\nIt is not all businesses that should have their own mobile application, but all businesses should be found on some kind of mobile smartphone application. There are what are called freelance applications and custom applications. others to consider are directory listing applications. <br/>\r\nCompanies have spent all their work and money to build an application that can help you reach new customer, grow your business and bring convenience to your users without you having to build one on your own. This could be a plus for new businesses. As a starting point you can use transport service booking platforms such as <a href=\"https://www.merchantcouriers.co.zw \" <button> Merchant Couriers </button></a> , to offer your freight delivery, taxi pickup, or even tow truck recovery at your convenience.<br/>\r\nWhy spend a lot of money developing, instead of joining a proven system and working with that and seeing what your clients love the most, then building one later?\r\n<br/><br/>\r\nKey #3 Your business should be able to collect payments online<br/><br/>\r\nAt the end of the day doing business online, is not only about informing customers about your services, where you are located, or what you are about. Make it easier fro clients or even new customers to book your transportation services online. Ecommerce is about convenience, and as long as people can find it easier to use your services or buy your products, then they should. Pre-built platforms such as merchant couriers, are the best transportation services platforms to join forces with. Simply because customers can pay online for a transportation service booking they have made.\r\n\r\n<br/><br/>\r\n\r\nThese are some of the key factors why we believe your business should take advantage of the internet business opportunity. That way your business grows as the economic trends shift.\r\n\r\n<br/><br/>\r\nIf you are in the transportation services industry, we encourage you to try Merchant Couriers, a transport services platform, that will help you get more customers and grow your business, without having to build the technology yourself. Best of all, both individuals and companies can take advantage of this.\r\n\r\n\r\n                         Click here to         <a href=\"https://mailchi.mp/ac66e56843f9/merchant-couriers-transport-service-provider-signups\" <button> Signup </button></a>  and start using the Merchant Couriers platform.\r\n', 'Mar 19 2018', 'Mobile app.png', '2018-03-19 15:04:12'),
(14, 'Happy Zhou', 'Business Update Announcement', 'News', 'As a strategic business move, we have resolved to temporarily *discontinue* the *taxi and tow truck service offerings* until further notice. <br/>We are in the process of improving our technology to suit these industries. Further information will be provided once these services are reinstated. Service offerings for freight, haulage and parcel delivery will continue as normal.\r\n<br/> Meanwhile, we thank all drivers that registered with us in the above respective areas. Thank you for your patience and participation thus far. Any inconvenience is sincerely regreted. <br/>\r\nRegards<br/>\r\nHappy Zhou\r\n(Merchant Couriers Operations Director)', 'April 03 2018', 'Screenshot_20171022-073950.png', '2018-04-03 17:52:01'),
(15, 'Marketing', 'Work Part Time, Refer Someone & Earn Income with this Affiliate Marketing Program', 'Advertising', '*Work Part Time, Refer Someone & Earn Income with this Affiliate Marketing Program*\r\n</br></br>\r\nHave you been looking for a job and getting none. Well this might just be for you. Here\'s an opportunity with a Zimbabwe startup, *Merchant Couriers* (found at merchantcouriers.co.zw)\r\n</br></br>\r\nMerchant Couriers Affiliate Program is an advertising (marketing and sales) program that spearheads the advertising strategies of our company. Through our affiliate program individuals anywhere in Zimbabwe can earnÃÂ income by sharing referral links, text messages, company flyer images with businesses, friends, family and other channels that need courier deliveries, furniture moving trucks, and freight & logistics services. \r\n</br></br>\r\nAffiliates share through their websites, display banners, blogs, forums, social media, facebook, twitter, linkedin, google+, social groups,\r\nincluding messaging platforms such as whatsapp, facebook messenger,  normal sms messaging and more chat rooms and other online media. When someone clicks and signup to use our services, you earn! Start your part time job and get paid weekly by signing up to this program!\r\n</br></br>\r\nThis is a high revenue sharing program anf your income is highly dependant on your efforts as a marketer and your personal strategy. You have room to be creative using our marketing tools:ÃÂ EarnÃÂ ÃÂ 10% commissions per every registered and booked customerÃÂ who  you reffered with your unique user id and link. You will earn income for the lifetime a reffered customer remains a Merchant Couriers customer and books services with us.\r\n\r\nHow to earn through this merchantcouriers.co.zw/affiliate.user program.\r\n\r\n</br></br>\r\nÃÂ - Visit the link   merchantcouriers.co.zw/affiliate.user click join now, read the program terms and conditions and register an account on the page for FREE.\r\n</br></br>\r\n-Open your account go to your profile and add your payment information (this can also be done later, when you claim your first payout)\r\n</br></br>\r\nÃÂ - Sharewith your contacts, on mobile, social media, email and your website to earn 10% when a customer signs up, books our servives, pays in full and services are completed.\r\n</br></br>\r\nÃÂ - Get payment at the end of the week (min 10$) through Ecocash or Bank transfer. Make sure to register your ecocash number in the account profile page.\r\n</br></br>\r\nÃÂ - Refer using the link or buttons in your dashboard home page and you will earn when customers signup through your shared links and book delivery services.\r\n</br></br>\r\n*Terms & Conditions Apply*\r\n*Limited Spaces Available*\r\n*One account allowed per user* *No spam policy applies*', 'July 14 2018', '20180712_123849_0001.png', '2018-07-12 13:00:27');
