INSERT INTO `contact_reply` (`ID`, `Date`, `Name`, `Subject`, `Email`, `phone`, `message`, `reply_id`, `replied_by`) VALUES
(1, '2018-01-19 14:50:25', 'Happy Zhou', 'Looking for a courier', 'zgarikai@gmail.com', '+263772467352', 'Hi Victor. Thank you for getting in touch we understand someone got in touch with you.  Due to internal changes we have removed the courier partnering option for the time being until further notice. We are working on a better way to arrange partnerships and we will update all our clients when the service is ready.\r\n\r\nThank you for your interest, we trust you will get exactly what you need.', 10, NULL),
(2, '2018-01-29 09:52:28', 'Happy Zhou', 'Registration', 'zgarikai@gmail.com', '+263772467352', 'Hi Tamira, \r\n\r\nKindly try to register again this time on merchant couriers website, note that we have updated our approach and cars will be acting as taxi\'s and delivery vehicles also. So you can either do taxi or parcel delivery. Its much easier to register now. Please try it again.\r\n\r\nAny issue you cant contact me and i\'ll be happy to assist.\r\n\r\nRegards\r\n\r\nHappy', 9, NULL),
(3, '2018-02-08 19:58:30', 'Happy Zhou', 'Contact for trucks', 'zgarikai@gmail.com', '+263772467352', 'Greetings Simbarashe, thank you for getting in touch. Whats the name of your company and may you kindly contact on 0772467352 or reply to this email. We don\'t buy trucks but if you want us to register your drivers on our system. We can help with that.\r\n\r\nRegards\r\nHappy Zhou', 11, NULL),
(4, '2018-02-20 11:53:26', 'Happy Zhou', 'Looking For Trucks', 'zgarikai@gmail.com', '+263772467352', 'Hi Jesmie Ashley\r\nThank you for your inquiry, kindly log onto our website signup for an account and book each job (this takes 3 minutes or less). You can enter your request or inquiry through our booking form, make sure you enter all details required. We can only offer trucks when we have all that information requested on our booking forms. Once received we will advise you, of the trucks available.\r\n\r\nRegards', 14, NULL),
(5, '2018-02-20 12:06:14', 'Happy Zhou', 'Registering Several Trucks', 'zgarikai@gmail.com', '+263772467352', 'Hello Tarirai\r\nThank you for getting in touch with us sorry we have replied late.\r\nTo register each truck kindly provide information for each vehicle as follows, \r\n-Full Driver (Company Name) Name\r\n-Address\r\n-Mobile Phone Number (can be the company mobile phone number)\r\n-Email (can be the company email)\r\n-Date of Birth\r\n-Vehicle Make (Model + Engine Capacity if you know it)\r\n-Manufacture Year\r\n-Number plate\r\n-If truck have brand of truck and model\r\n- If its a truck have your Truck Tonnage\r\n-1 profile photo of the driver\r\n-Photo of Registration and Insurance on vehicle windscreen\r\n-Photo of each truck drivers licence \r\n\r\nAfter registration each truck will have a login.\r\n\r\nMy number is 0772467352. A call or whatsapp will do.\r\n\r\nWe look forward to partnering with you and working together.\r\n', 13, NULL),
(6, '2018-02-22 10:56:04', 'Happy Zhou', 'Truck registrations', 'zgarikai@gmail.com', '+263772467352', 'Dear Tari,\r\nThank you for expressing interest to register with us on Merchant Couriers.\r\nMay you kindly advise us if you got our email reply with guidelines on how to register your trucks.\r\n\r\nRegards\r\n\r\nHappy Zhou', 13, NULL),
(7, '2018-02-22 10:57:38', 'Happy Zhou', 'Order Delay', 'zgarikai@gmail.com', '+263772467352', 'Please bare with us your order is on the way. \r\n\r\nSincere apologies for inconvenience caused.\r\n\r\nregards\r\n\r\nHappy Zhou', 8, NULL),
(8, '2018-02-23 14:19:17', 'Happy Zhou', 'Order delay', 'zgarikai@gmail.com', '+263772467352', 'Hi thanks for your enquiry. We have checked your order and it will artive today before end of day. \r\n\r\nSorry for the inconvenience.\r\n\r\nRegards\r\n\r\nHappy', 8, NULL),
(9, '2018-02-23 20:31:14', 'Happy Zhou', 'Order delay', 'zgarikai@gmail.com', '+263772467352', 'thanks for the update. We have checked your order abd it seems to be arrivibg any time from now.\r\n\r\nRegards\r\n\r\nHappy Zhou', 8, NULL),
(10, '2018-02-23 23:22:30', 'Happy Zhou', 'Order delay', 'zgarikai@gmail.com', '+263772467352', 'thanks for your patience. ', 8, NULL),
(11, '2018-02-28 08:58:54', 'Happy Zhou', 'Truck Registrations', 'zgarikai@gmail.com', '+263772467352', 'Dear Tari, Thank you for expressing interest to register with us on Merchant Couriers. May you kindly advise us if you got our email reply with guidelines on how to register your trucks. \r\nAlso we can send someone to your company or yourself and help with registration procedures for multiple trucks.\r\nRegards \r\nHappy Zhou(Merchant couriers director) \r\n', 13, NULL),
(12, '2018-02-28 08:59:33', 'Happy Zhou', 'Looking For Trucks to Load', 'zgarikai@gmail.com', '+263772467352', 'Hi Jesmie Ashley Thank you for your inquiry, kindly log onto our website signup for an account and book each job (this takes 3 minutes or less). You can enter your request or inquiry through our booking form, make sure you enter all details required. We can only offer trucks when we have all that information requested on our booking forms. Once received we will advise you, of the trucks available. Regards ', 14, NULL),
(13, '2018-02-28 09:03:08', 'Happy Zhou', 'Contact for your truck and vehicle registrations', 'zgarikai@gmail.com', '+263772467352', 'Greetings Mr S Choga. thank you for getting in touch.  if you want us to register your drivers on our system. We can help with that. \r\nAlternatively we can meet in Harare Borrowdale, at Pomona for formal introductions and assistance with truck registrations, as you may have been informed we are getting loading requests and we would like to bring you some good business.\r\nPlease contact me 0772467352 for meeting arrangements. Hope we can meetup soon.\r\nRegards Happy Zhou (Merchant couriers director)\r\n', 11, NULL),
(14, '2018-02-28 09:04:57', 'Happy Zhou', 'Driver Job Followup', 'zgarikai@gmail.com', '+263772467352', 'Hi Tamira, \r\n\r\nHope you are doing well this 2018, i wanted to follow up with you and see where you are with your car?\r\n\r\nKindly try to register again this time on merchant couriers website, note that we have updated our approach and cars will be acting as taxi\'s and delivery vehicles also. So you can either do taxi or parcel delivery. Its much easier to register now. Please try it again. Any issue you can contact me 0772467352 and i\'ll be happy to assist. Regards.\r\n', 9, NULL),
(15, '2018-02-28 09:05:48', 'Happy Zhou', 'Great work', 'zgarikai@gmail.com', '+263772467352', 'Thank you for your feedback, and your problem is being resolved.', 8, NULL),
(16, '2018-03-13 22:20:05', 'Happy Zhou', 'Registering Your Trucks For Freight Booking', 'zgarikai@gmail.com', '+263772467352', 'We noticed you haven\'t registered your trucks yet. Could you fru ish us with a phone number or address for your offices sp that we can come and help you register your trucks? \r\n\r\nRegards\r\n\r\nHappy Zhou', 13, NULL),
(17, '2018-03-27 12:47:08', 'Takwada Mupho Sandra', 'VEHICLE REGISTRATION', 'mphotakwada@yahoo.com', '0783537130', 'Hello Tari, responding to the issue you raised earlier on multiple registrations of vehicles, i have noticed you haven\'t registered as yet, if you are facing any difficulty in doing so, may you contact us on 0779495409 and i will go through the entire process with you, also if you have any inquiries please feel free to contact us. may you also provide a contact number so that we contact you. Thank you & Regards\r\nSandra. Hr Officer ', 13, NULL),
(18, '2018-08-10 08:58:46', 'Happy Zhou', 'Serving Your Business Needs', 'zgarikai@gmail.com', '+263772467352', '<p>Hi Pellani,</p>\r\n<p>Sorry for a delayed response, thank you for your inquiry please note that when it comes to your business, we have to meet briefly or talk over the phone to understand what your company does and serve your needs.</p>\r\n<p>However, yes in terms of eCommerce integration with your business we can arrange a fixed rate for your deliveries to your customers. This will be merged with our delivery app on your business website or account.</p>\r\n<p>Kindly whatsapp me on 0772467352 or send me your number via email to merchantcouriers1@gmail.com</p>\r\n<p>I look forward to helping you with all your delivery needs.</p>\r\n<p>Regards</p>\r\n<p>Happy Zhou</p>', 74, NULL),
(19, '2018-08-10 09:02:02', 'Happy Zhou', 'Business Needs', 'zgarikai@gmail.com', '+263772467352', '<p>Hi Pellani,</p>\r\n<p>Sorry for a delayed response, thank you for your inquiry please note that when it comes to your business, we have to meet briefly or talk over the phone to understand what your company does and serve your needs.</p>\r\n<p>However, yes in terms of eCommerce integration with your business we can arrange a fixed rate for your deliveries to your customers. This will be merged with our delivery app on your business website or account.</p>\r\n<p>Kindly whatsapp me on 0772467352 or send me your number via email to merchantcouriers1@gmail.com</p>\r\n<p>I look forward to helping you with all your delivery needs.</p>\r\n<p>Regards</p>\r\n<p>Happy Zhou</p>', 8, NULL),
(20, '2018-08-10 09:08:48', 'Happy Zhou', 'Serving Your Business Needs', 'zgarikai@gmail.com', '+263772467352', '<p>Dear Pellani,</p>\r\n<p>I also forgot to mention that, yes our rate per mile is fixed already. So the system calculates with that one fixed rate from the pickup to the dropoff.</p>\r\n<p>Feel free to get in touch over the phone number below.</p>\r\n<p>Regards</p>\r\n<p>Happy Zhou</p>', 74, NULL),
(21, '2018-08-28 21:29:32', 'Happy Zhou', 'Parcel Delivery Around Harare', 'zgarikai@gmail.com', '+263772467352', 'Greetings Rukudzo\r\n\r\nKindly not that to get pricez of each delivery around harare you may use the get quote feature on our website and enter the pickup and drop off address for local deliveries. \r\n\r\nThe delivery of each parcel will differe by pickup and drop off location. Including how many items plus weight. \r\n\r\nHowever if it is the same distance a price can be generated certainly. I am swnding you a message on whatsapp that way i can get a better understanding of what you would like to deliver in harare, how often and the quantities.\r\n\r\nRegards\r\n\r\nHappy ', 76, NULL);
INSERT INTO `customer_alerts` (`id`, `date`, `msg`, `subject`) VALUES
(1, '2018-08-05 15:42:18', '<p>As our customer we would like for you to experience the best when it comes to your delivery needs.</p>\r\n<p><strong>Bringing you convenience with Bootspace&nbsp;</strong></p>\r\n<p>We have designed a product for your needs. It is called Bootspace, a parcel delivery service by us at merchant couriers that you can use to send your parcels at your best convenience.</p>\r\n<p><strong>Let\'s reflect for a second..</strong></p>\r\n<p>Are there times when you want to send something somewhere yet you are busy?&nbsp; maybe you had to either do it yourself, send it with a friend or even go to a bus terminus find a bus driver or conductor and send through them.</p>\r\n<p>Chances are you\'ve done this either for sending to your friend, relative, or customers somewhere. We know it has happened to most if not all of us that\'s why we created Bootspace.</p>\r\n<p><strong>Why use it? Our promise....</strong></p>\r\n<p>With bootspace you can send a parcel or any legal goods from whereever you are by a 1minute booking on our Android app. From within your city within a few hours or outside to other cities and be sure it will arrive within 24hrs. Best of all you can send it whether you are home, at work or have other committments.</p>\r\n<p>When you book a delivery on Merchant Couriers, we\'l come to pick it up and deliver it for you right from where you are.</p>\r\n<p><strong>Is it safe? Security....</strong></p>\r\n<p>Our system helps you track your delivery through sms and email updates as the delivery is taking place. From the time it is collected from the pickup address to the time it is delivered at its destination.</p>\r\n<p>You can also contact&nbsp; anytime 24hrs around the clock. And you can make your booking anytime of the day or night.</p>\r\n<p><strong>Get a delivery quote from your phone</strong></p>\r\n<p>To know how much it costs simply visit our website and get a quote which you can also email to yourself or your clients if you are a business owner. Whatever it is you can know how much it costs before committing.</p>\r\n<p>Next time you desire to send something . Remember there is bootspace designed just for you.</p>\r\n<h3>Download our booking app <a href=\"https://www.merchantcouriers.co.zw/mobile_apps/MerchantCouriersBooking.apk\" target=\"_blank\" rel=\"noopener noreferrer\" data-saferedirecturl=\"https://www.google.com/url?q=https://www.merchantcouriers.co.zw/mobile_apps/MerchantCouriersBooking.apk&amp;source=gmail&amp;ust=1532594571605000&amp;usg=AFQjCNE03Pd3-PPh5ICdIDv8XBgGElY5lA\">here</a> to book a delivery at anytime using your phone.</h3>\r\n<p>Enjoy the convenience</p>\r\n<p>Merchant Couriers Customer Service</p>', 'Send a parcel from wherever you are!    '),
(2, '2018-08-16 22:41:53', '<p>We have recently had some new bookings coming through our system and we wanted to familiarise all clients with all our service offerings available as of this month of August 2018.</p>\r\n<p><strong>Get Your First 10% Discount</strong></p>\r\n<p>All new customers are being awarded a 10% discount for first time booking that you do on our platform.</p>\r\n<p><strong>Get A Quote In 15seconds</strong></p>\r\n<p>Remember before booking you can use the get quote feature on the website or in the customer booking Android application to know the cost of any of the servuces we offer before you book. You can also share this quote via email to your colleagues, husband, wife,&nbsp; family, friends as you weigh your best options.</p>\r\n<p><strong>Whats On Offer</strong></p>\r\n<p>1. <em>Inner City Parcel Deliveries</em></p>\r\n<p><em>In this service you can a parcel&nbsp; (anything send-able) anywhere within Harare also up to Ruwa, Chitungwiza, Chishawasha Hills and other surbubs surrounding our beautiful sunshine city.</em></p>\r\n<p><em>2. Heavy Freight Delivery</em></p>\r\n<p><em>Our freight offering comes in two categories. We have the local and international bookings. All of these are booked online. At present moment we only book heavy freight loads for full truck sizes ranging from 3tonne trucks to 18tonne trucks.</em></p>\r\n<p><em>3. House Moving (Booked Under Freight Delivery Option)</em></p>\r\n<p><em>We have recently added furniture moving as a service for moving in Harare and it has proved to be worthwhile for those who managed to move by us. We guarantee, comfortable moving withinimal breakages and favorable moving charges.</em></p>\r\n<p><strong>Online Payments</strong></p>\r\n<p>We have designed our booking to work together with some of the most common payment options available such as Ecocash, Telecash, Zimswitch, Visa, Mastercard, Zipit. Our payments are processed through paynow zimbabwe at booking. This means all you have to do is book and pay for you to get your booking attended to fast enough.</p>\r\n<p><strong>Share With A Friend + Earn</strong></p>\r\n<p>We ask you to refer our platform to one or two contacts via the mobile app login share butyons on the login page or on our website through the share buttons as well.</p>\r\n<p>Customers can also earn 10% for refferrals through the affiliate program. Refer your network, businesses , family and friends to us, and stand a good chance to earn some extra income. To join this program, visit our website or use the booking app and find the* join affiliate program* link on the menu.</p>\r\n<p>Enjoy convenient booking on our apps and let us deliver for you from the comfort of your home, office or even when on holiday. We\'l pick it and deliver it for you.</p>\r\n<p>Happy Weekend!</p>\r\n<p>Merchant Couriers Customer Service</p>\r\n<p>&nbsp;</p>', 'At Your Service..'),
