INSERT INTO `driver_alerts` (`id`, `date`, `msg`, `subject`) VALUES
(14, '2018-09-26 14:34:44', 'Hello, download your delivery app on merchantcouriers.co.zw get jobs via phone. See it work! Watch: https://youtu.be/0e5NpHCGiZs\r\n& https://youtu.be/1-6KISWvXN4 ', 'Delivery App Training'),
(15, '2018-11-20 15:30:21', 'Dear transporter. Having secured some contracts for local and intercity freight loads, as a requirement from business partners. To take advantage of this, kindly email copies to merchantcouriers1@gmail.com. Your truck\'s registration book, current licence disk, current 3rd party insurance, transport permit (if available), and fitness certificate of your trucks. This is for  3.5t to 34t trucks. Merchant Couriers Driver Recruitment Team.', 'Driver Documents'),
(16, '2018-12-25 18:42:55', 'Merchant Couriers wishes you a Merry Christmas & Happy New Year. Thank you for driving with us in 2018. Drive safely and deliver on time. Stay alert for new delivery jobs in 2019!', 'Christmas Message and Promo');
