(151, '_transient_dash_88ae138922fe95674369b1cb3d215a2b', '<div class=\"rss-widget\"><ul><li><a class=\'rsswidget\' href=\'https://wordpress.org/news/2017/03/wordpress-4-7-3-security-and-maintenance-release/\'>WordPress 4.7.3 Security and Maintenance Release</a> <span class=\"rss-date\">March 6, 2017</span><div class=\"rssSummary\">WordPress 4.7.3 is now available. This is a security release for all previous versions and we strongly encourage you to update your sites immediately. WordPress versions 4.7.2 and earlier are affected by sixÂ security issues: Cross-site scripting (XSS) viaÂ media file metadata. Â Reported by Chris AndrÃ¨ Dale, Yorick Koster,Â and Simon P. Briggs. Control characters can trick redirect [&hellip;]</div></li></ul></div><div class=\"rss-widget\"><ul><li><a class=\'rsswidget\' href=\'https://wptavern.com/how-to-find-the-age-of-a-plugin-hosted-in-the-wordpress-plugin-directory\'>WPTavern: How to Find the Age of a Plugin Hosted in the WordPress Plugin Directory</a></li><li><a class=\'rsswidget\' href=\'https://wptavern.com/php-5-6-is-now-the-most-widely-used-php-version\'>WPTavern: PHP 5.6 Is Now the Most Widely Used PHP Version</a></li><li><a class=\'rsswidget\' href=\'https://ma.tt/2017/03/on-the-james-altucher-show/\'>Matt: On the James Altucher Show</a></li></ul></div><div class=\"rss-widget\"><ul><li class=\"dashboard-news-plugin\"><span>Popular Plugin:</span> Google Analytics Dashboard for WP&nbsp;<a href=\"plugin-install.php?tab=plugin-information&amp;plugin=google-analytics-dashboard-for-wp&amp;_wpnonce=9dfa7feb18&amp;TB_iframe=true&amp;width=600&amp;height=800\" class=\"thickbox open-plugin-details-modal\" aria-label=\"Install Google Analytics Dashboard for WP\">(Install)</a></li></ul></div>', 'no'),
