(1, 1, '2017-03-24 00:28:04', '2017-03-24 00:28:04', 'Welcome to WordPress. This is your first post. Edit or delete it, then start writing!', 'Hello world!', '', 'publish', 'open', 'open', '', 'hello-world', '', '', '2017-03-24 00:28:04', '2017-03-24 00:28:04', '', 0, 'http://merchantcouriers.co.zw/wp/?p=1', 0, 'post', '', 1),
(2, 1, '2017-03-24 00:28:04', '2017-03-24 00:28:04', 'This is an example page. It\'s different from a blog post because it will stay in one place and will show up in your site navigation (in most themes). Most people start with an About page that introduces them to potential site visitors. It might say something like this:\r\n<blockquote>Hi there! I\'m a bike messenger by day, aspiring actor by night, and this is my website. I live in Los Angeles, have a great dog named Jack, and I like piÃ±a coladas. (And gettin\' caught in the rain.)</blockquote>\r\n...or something like this:\r\n<blockquote>The XYZ Doohickey Company was founded in 1971, and has been providing quality doohickeys to the public ever since. Located in Gotham City, XYZ employs over 2,000 people and does all kinds of awesome things for the Gotham community.</blockquote>\r\nAs a new WordPress user, you should go to <a href=\"http://merchantcouriers.co.zw/wp/wp-admin/\">your dashboard</a> to delete this page and create new pages for your content. Have fun!\r\n\r\n', 'Sample Page', '', 'publish', 'closed', 'open', '', 'sample-page', '', '', '2017-03-24 21:12:53', '2017-03-24 21:12:53', '', 0, 'http://merchantcouriers.co.zw/wp/?page_id=2', 0, 'page', '', 0),
